package com.esoterica.game.api\n\nimport io.micronaut.http.*\nimport io.micronaut.http.filter.*\nimport jakarta.inject.Singleton\n\n@Singleton\nclass AuthFilter : HttpServerFilter {\n    override fun doFilter(request: HttpRequest<*>, chain: ServerFilterChain) =\n        if (request.headers["X-API-KEY"] != "dev-key") {\n            io.micronaut.core.async.publisher.Publishers.just(HttpResponse.unauthorized<Any>())\n        } else chain.proceed(request)\n}\n